INSERT INTO public."User" VALUES ('cmn2mgvi10003lyec6ijhnvzb', 'ruobin', '17610357266', '$2b$10$5m1btfRX7FlrgYnb0JAZOuGZinkdGtfdldxV1MC9kMEEiSaiFHodG', NULL, NULL, NULL, 'ADMIN', 'cmn2n5vf6000clyecv2csc7bx', '2026-03-23 03:24:35.065', '2026-03-23 03:44:01.38') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojie00003iecglvd58p0', '烤鱼', 'OTHER', '[{"name": "河鲈鱼", "unit": "", "amount": ""}, {"name": "炒料原材料（胡萝卜", "unit": "", "amount": ""}, {"name": "洋葱", "unit": "", "amount": ""}, {"name": "香芹", "unit": "", "amount": ""}, {"name": "蒜", "unit": "", "amount": ""}, {"name": "小米辣", "unit": "", "amount": ""}, {"name": "香菇）", "unit": "", "amount": ""}, {"name": "喜欢的各种配菜", "unit": "", "amount": ""}, {"name": "油", "unit": "", "amount": ""}, {"name": "黄豆酱（4-5勺）", "unit": "", "amount": ""}, {"name": "牛油火锅底料（一小块）", "unit": "", "amount": ""}, {"name": "花椒（一小把）", "unit": "", "amount": ""}, {"name": "盐", "unit": "", "amount": ""}, {"name": "糖", "unit": "", "amount": ""}, {"name": "鸡精", "unit": "", "amount": ""}]', '[{"order": 1, "content": "备料：河鲈鱼杀好后去内脏鱼鳍，两面各片2-3刀，鱼身均匀涂抹十三香、盐、胡椒粉，刀口处塞入姜片，用保鲜膜包起来，腌制30min以上备用"}, {"order": 2, "content": "胡萝卜一根、香芹半斤、洋葱一个、香菇4-5个、蒜一头、小米辣3-4个切丁备用，量酌情加减"}, {"order": 3, "content": "起锅烧油，油热放入腌好的鱼两面煎，煎到两面金黄可捞起放入煮锅中"}, {"order": 4, "content": "炒料：煎鱼油小火微热，放入黄豆酱（豆瓣酱）不断翻炒，油色微黄放入牛油火锅底料和花椒继续翻炒，火锅底料溶解后放入胡萝卜丁、香芹丁、洋葱丁、香菇丁、蒜和小米辣不断翻炒，可以适当多炒一会儿以便味道融合，放入两勺盐、两勺白糖、两勺鸡精调味，翻炒均匀后可盖在煎好的鱼身上"}, {"order": 5, "content": "加水磨过3/4鱼身，水开后加入配菜，熟了可食用。"}]', '/uploads/cmn2oojie00003iecglvd58p0.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.006', '2026-03-23 04:35:30.751') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojjv00013iec2n4asisv', '三汁焖锅', 'OTHER', '[{"name": "鸡翅", "unit": "", "amount": ""}, {"name": "大虾", "unit": "", "amount": ""}, {"name": "香芹", "unit": "", "amount": ""}, {"name": "洋葱", "unit": "", "amount": ""}, {"name": "胡萝卜", "unit": "", "amount": ""}, {"name": "玉米", "unit": "", "amount": ""}, {"name": "金针菇", "unit": "", "amount": ""}, {"name": "蒜", "unit": "", "amount": ""}, {"name": "耗油三勺", "unit": "", "amount": ""}, {"name": "番茄酱一勺", "unit": "", "amount": ""}, {"name": "料酒一勺", "unit": "", "amount": ""}, {"name": "老抽一勺", "unit": "", "amount": ""}, {"name": "胡椒粉一点点", "unit": "", "amount": ""}, {"name": "糖半勺", "unit": "", "amount": ""}]', '[{"order": 1, "content": "备菜：鸡翅划刀，香芹切段，胡萝卜切滚刀块，洋葱切片，玉米切段"}, {"order": 2, "content": "调料汁：把调料所列的料按比例放到一个碗中，可加一点黄豆酱"}, {"order": 3, "content": "开火倒油（中火），先把蒜炒香（整瓣即可），倒入香芹、洋葱、胡萝卜翻炒几下"}, {"order": 4, "content": "把翻炒的菜铺底，摆上鸡翅、虾、玉米、金针菇等，均匀涂抹酱料，加一碗清水，盖上锅盖"}, {"order": 5, "content": "大火烧开转小火，焖15-20min即可。"}]', '/uploads/cmn2oojjv00013iec2n4asisv.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.059', '2026-03-23 04:35:31.511') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojk100023iec8oco0cwk', '黄焖鸡', 'OTHER', '[{"name": "鸡腿", "unit": "", "amount": ""}, {"name": "土豆/香菇等配菜", "unit": "", "amount": ""}, {"name": "葱姜蒜", "unit": "", "amount": ""}, {"name": "小米辣", "unit": "", "amount": ""}, {"name": "油", "unit": "", "amount": ""}, {"name": "料酒", "unit": "", "amount": ""}, {"name": "八角", "unit": "", "amount": ""}, {"name": "黄豆酱", "unit": "", "amount": ""}, {"name": "耗油", "unit": "", "amount": ""}, {"name": "生抽", "unit": "", "amount": ""}, {"name": "老抽", "unit": "", "amount": ""}, {"name": "鸡精", "unit": "", "amount": ""}]', '[{"order": 1, "content": "鸡腿切块焯水，冷水下锅，放入葱姜、料酒，焯水后用水冲洗"}, {"order": 2, "content": "起锅烧油，放八角、姜片和蒜、葱段炝锅，倒入焯好的鸡腿肉翻炒"}, {"order": 3, "content": "放入料酒一勺，黄豆酱一勺，耗油一勺，生抽一勺，老抽一点点，继续翻炒"}, {"order": 4, "content": "放入配菜，加水至没过鸡腿肉，大火烧开"}, {"order": 5, "content": "转中火炖10min左右，加一点小米辣和鸡精，出锅即食。"}]', '/uploads/cmn2oojk100023iec8oco0cwk.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.065', '2026-03-23 04:35:32.27') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojk600033iecgtigksse', '牛奶麻辣烫', 'OTHER', '[{"name": "麻辣烫喜欢的所有菜", "unit": "", "amount": ""}, {"name": "葱姜蒜", "unit": "", "amount": ""}, {"name": "牛奶", "unit": "", "amount": ""}, {"name": "牛油火锅底料一块", "unit": "", "amount": ""}, {"name": "郫县豆瓣酱1-2勺", "unit": "", "amount": ""}, {"name": "耗油", "unit": "", "amount": ""}, {"name": "生抽", "unit": "", "amount": ""}, {"name": "白糖", "unit": "", "amount": ""}, {"name": "盐", "unit": "", "amount": ""}, {"name": "鸡精", "unit": "", "amount": ""}]', '[{"order": 1, "content": "姜切片，葱切段，蒜整瓣"}, {"order": 2, "content": "起锅烧油，葱姜蒜炝锅，先后放入火锅底料和郫县豆瓣酱炒出红油"}, {"order": 3, "content": "加一袋牛奶和热水烧开，放入耗油、生抽、白糖、盐、鸡精调味"}, {"order": 4, "content": "按照食材需要煮的时间先后放入锅内，煮熟捞出即可食用。"}]', '/uploads/cmn2oojk600033iecgtigksse.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.07', '2026-03-23 04:35:33.072') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojkb00043iecvt5ewh01', '打卤面', 'STAPLE', '[{"name": "手擀面", "unit": "", "amount": ""}, {"name": "西红柿", "unit": "", "amount": ""}, {"name": "鸡蛋", "unit": "", "amount": ""}, {"name": "五花肉", "unit": "", "amount": ""}, {"name": "香菇", "unit": "", "amount": ""}, {"name": "黄瓜", "unit": "", "amount": ""}, {"name": "蒜", "unit": "", "amount": ""}, {"name": "海天黄豆酱", "unit": "", "amount": ""}, {"name": "糖", "unit": "", "amount": ""}, {"name": "盐", "unit": "", "amount": ""}, {"name": "鸡精", "unit": "", "amount": ""}, {"name": "生抽/海鲜酱油", "unit": "", "amount": ""}, {"name": "香油", "unit": "", "amount": ""}]', '[{"order": 1, "content": "说明：有四个卤-肉酱、西红柿鸡蛋、黄瓜丝、蒜汁，拌食"}, {"order": 2, "content": "备料：五花肉切小丁、香菇切小丁，西红柿切小块、鸡蛋打散；黄瓜切丝，蒜切沫"}, {"order": 3, "content": "肉酱：油微热下肉丁（先下肥的翻炒两下再下瘦的），肉丁炒变色后放入香菇丁，翻炒均匀，加入两大勺黄豆酱继续翻炒，均匀后加入一碗水，小火烧2min左右，微粘稠状态可出锅备用"}, {"order": 4, "content": "西红柿鸡蛋：油热后放入鸡蛋，成型后打散盛出备用，起锅烧油，热后放入西红柿快速翻炒，待西红柿出汁微烂放入鸡蛋搅拌均匀，加入2-3勺白糖，少量盐和鸡精，翻炒均匀后出锅备用"}, {"order": 5, "content": "蒜汁：大蒜切沫，放入碗中，加入没过蒜末的生抽，加入少许香油搅拌均匀"}, {"order": 6, "content": "面煮熟以后过凉水，盛到盘子中，分别加入肉酱、西红柿鸡蛋、蒜汁和黄瓜丝，搅拌均匀，就可以大口吃啦！"}]', '/uploads/cmn2oojkb00043iecvt5ewh01.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.075', '2026-03-23 04:35:33.859') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojkj00053iec8sj15dlv', '麻酱拌面', 'STAPLE', '[{"name": "手擀面", "unit": "", "amount": ""}, {"name": "黄瓜", "unit": "", "amount": ""}, {"name": "炸花生米", "unit": "", "amount": ""}, {"name": "肥牛（或其他喜欢的荤菜）", "unit": "", "amount": ""}, {"name": "香菜", "unit": "", "amount": ""}, {"name": "蒜", "unit": "", "amount": ""}, {"name": "小葱", "unit": "", "amount": ""}, {"name": "白芝麻", "unit": "", "amount": ""}, {"name": "辣椒面", "unit": "", "amount": ""}, {"name": "生抽", "unit": "", "amount": ""}, {"name": "耗油", "unit": "", "amount": ""}, {"name": "陈醋", "unit": "", "amount": ""}, {"name": "白糖", "unit": "", "amount": ""}, {"name": "芝麻酱", "unit": "", "amount": ""}]', '[{"order": 1, "content": "备料：蒜末、葱花、白芝麻、辣椒面，平铺在碗里浇上热油，然后加入2:2:1:1:1的生抽、麻酱、耗油、陈醋、白糖，搅拌均匀"}, {"order": 2, "content": "面条煮熟，捞出过凉水，碗里放入黄瓜丝、花生米、香菜以及煮好的肥牛，倒入酱汁搅拌均匀，就可以享用啦！"}]', '/uploads/cmn2oojkj00053iec8sj15dlv.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.083', '2026-03-23 04:35:34.625') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojkq00063iecy89a28dy', '素三鲜水饺', 'STAPLE', '[{"name": "面/饺子皮", "unit": "", "amount": ""}, {"name": "韭菜", "unit": "", "amount": ""}, {"name": "鸡蛋", "unit": "", "amount": ""}, {"name": "虾仁", "unit": "", "amount": ""}, {"name": "木耳碎（可不放）", "unit": "", "amount": ""}, {"name": "油", "unit": "", "amount": ""}, {"name": "耗油", "unit": "", "amount": ""}, {"name": "十三香", "unit": "", "amount": ""}, {"name": "盐", "unit": "", "amount": ""}, {"name": "鸡精", "unit": "", "amount": ""}]', '[{"order": 1, "content": "准备饺子皮（和面要稍微硬一点）"}, {"order": 2, "content": "准备馅：鸡蛋打散，热油（稍多一点）下锅关火立即用筷子搅散备用，韭菜切碎、虾仁切丁状（别太碎）"}, {"order": 3, "content": "把鸡蛋、韭菜、虾仁放到一起，加耗油（至少三勺）、十三香、盐适量、鸡精，搅拌均匀"}, {"order": 4, "content": "包"}, {"order": 5, "content": "煮"}, {"order": 6, "content": "吃"}, {"order": 7, "content": "刷碗。"}]', '/uploads/cmn2oojkq00063iecy89a28dy.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.09', '2026-03-23 04:35:35.412') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojku00073iecfh7exgqn', '卤肉饭', 'STAPLE', '[{"name": "米饭", "unit": "", "amount": ""}, {"name": "五花肉", "unit": "", "amount": ""}, {"name": "香菇", "unit": "", "amount": ""}, {"name": "洋葱", "unit": "", "amount": ""}, {"name": "姜", "unit": "", "amount": ""}, {"name": "蒜", "unit": "", "amount": ""}, {"name": "鸡蛋", "unit": "", "amount": ""}, {"name": "菜心", "unit": "", "amount": ""}, {"name": "料酒", "unit": "", "amount": ""}, {"name": "生抽", "unit": "", "amount": ""}, {"name": "老抽", "unit": "", "amount": ""}, {"name": "蚝油", "unit": "", "amount": ""}, {"name": "八角", "unit": "", "amount": ""}, {"name": "香叶", "unit": "", "amount": ""}, {"name": "桂皮", "unit": "", "amount": ""}, {"name": "冰糖", "unit": "", "amount": ""}, {"name": "盐", "unit": "", "amount": ""}]', '[{"order": 1, "content": "备菜：五花肉去皮切长丁，香菇切丁用水浸泡，洋葱切丁，姜蒜切沫，鸡蛋下锅煮5-6分钟备用"}, {"order": 2, "content": "热锅凉油，下洋葱姜蒜炒香，倒入五花肉丁翻炒至变色"}, {"order": 3, "content": "加入少量料酒、老抽，适量生抽、蚝油调味调色，翻炒均匀后加入香菇"}, {"order": 4, "content": "加入八角、香叶、桂皮继续翻炒，倒入泡香菇的水，放入几块冰糖，把鸡蛋剥皮下锅"}, {"order": 5, "content": "大火烧开以后转小火慢炖，20min左右可开大火收汁，夹出八角桂皮香叶，同时加盐调味"}, {"order": 6, "content": "菜心烫3分钟，与米饭，卤肉盛到一起，就可以享受啦！"}]', '/uploads/cmn2oojku00073iecfh7exgqn.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.094', '2026-03-23 04:35:36.187') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojla00083iec5u83vsz7', '网红方便面', 'STAPLE', '[{"name": "方便面", "unit": "", "amount": ""}, {"name": "西红柿", "unit": "", "amount": ""}, {"name": "鸡蛋", "unit": "", "amount": ""}, {"name": "喜欢的配菜", "unit": "", "amount": ""}]', '[{"order": 1, "content": "水烧开加入切成丁的西红柿煮出汤汁，加入蔬菜包煮1min"}, {"order": 2, "content": "放入干料和酱料煮1min，放入方便面"}, {"order": 3, "content": "煮熟即可食用。"}]', '/uploads/cmn2oojla00083iec5u83vsz7.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.11', '2026-03-23 04:35:36.962') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojlh00093iecdhs5xsh0', '炝拌土豆丝', 'VEGETABLE', '[{"name": "土豆", "unit": "", "amount": ""}, {"name": "干辣椒", "unit": "", "amount": ""}, {"name": "油", "unit": "", "amount": ""}, {"name": "花椒", "unit": "", "amount": ""}, {"name": "盐", "unit": "", "amount": ""}, {"name": "糖", "unit": "", "amount": ""}, {"name": "鸡精", "unit": "", "amount": ""}, {"name": "耗油", "unit": "", "amount": ""}]', '[{"order": 1, "content": "土豆切丝焯水，捞出过凉水，焯水时可加入一点白醋保持脆爽口感"}, {"order": 2, "content": "土豆丝捞出放入盘中，加盐（一点即可）、糖（一点即可），鸡精、耗油、花椒、干辣椒捏碎放在表面"}, {"order": 3, "content": "起锅烧热油（普通炒菜量），冒烟了把油浇到调料上，拌匀即可食用。"}]', '/uploads/cmn2oojlh00093iecdhs5xsh0.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.117', '2026-03-23 04:35:37.753') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojll000a3iecqq3xjx86', '凉拌茄子', 'VEGETABLE', '[{"name": "茄子", "unit": "", "amount": ""}, {"name": "香菜", "unit": "", "amount": ""}, {"name": "蒜", "unit": "", "amount": ""}, {"name": "小米辣", "unit": "", "amount": ""}, {"name": "生抽", "unit": "", "amount": ""}, {"name": "耗油", "unit": "", "amount": ""}, {"name": "醋", "unit": "", "amount": ""}, {"name": "香油", "unit": "", "amount": ""}]', '[{"order": 1, "content": "茄子削皮切细段（大小自己掌握即可），上锅蒸15min左右，倒掉汁水，放凉备用"}, {"order": 2, "content": "蒜切沫，小米辣切小段，香菜切小段，倒入茄子中"}, {"order": 3, "content": "加入一勺醋、一勺耗油、一勺生抽，半勺香油，一点点盐和鸡精，拌匀即可。"}]', '/uploads/cmn2oojll000a3iecqq3xjx86.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.121', '2026-03-23 04:35:38.524') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojls000b3iec1vc2cq13', '肉末茄子', 'MEAT', '[{"name": "茄子", "unit": "", "amount": ""}, {"name": "肉馅", "unit": "", "amount": ""}, {"name": "香菜", "unit": "", "amount": ""}, {"name": "小葱", "unit": "", "amount": ""}, {"name": "蒜", "unit": "", "amount": ""}, {"name": "小米辣", "unit": "", "amount": ""}, {"name": "生抽", "unit": "", "amount": ""}, {"name": "老抽", "unit": "", "amount": ""}, {"name": "耗油", "unit": "", "amount": ""}, {"name": "陈醋", "unit": "", "amount": ""}, {"name": "白糖", "unit": "", "amount": ""}, {"name": "淀粉", "unit": "", "amount": ""}, {"name": "胡椒粉", "unit": "", "amount": ""}]', '[{"order": 1, "content": "茄子削皮切条上锅蒸熟，挤掉水分备用，葱蒜切沫"}, {"order": 2, "content": "调一个料汁：2勺生抽，多半勺老抽，1勺耗油，1勺陈醋，半勺白糖，一勺淀粉，2勺清水，搅拌均匀备用"}, {"order": 3, "content": "起锅烧油，油热后下肉馅翻炒，加入一点胡椒粉，然后放入（小米辣和）一半蒜末"}, {"order": 4, "content": "肉馅变色翻炒均匀后加入茄子翻炒，再倒入备好的料汁炒匀"}, {"order": 5, "content": "关火后放入葱花和剩余蒜末，搅拌均匀即可。"}]', '/uploads/cmn2oojls000b3iec1vc2cq13.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.128', '2026-03-23 04:35:39.259') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojlw000c3iecrfcmidp3', '水煮肉片', 'MEAT', '[{"name": "小里脊肉", "unit": "", "amount": ""}, {"name": "青菜", "unit": "", "amount": ""}, {"name": "牛油火锅底料", "unit": "", "amount": ""}, {"name": "郫县豆瓣酱", "unit": "", "amount": ""}, {"name": "耗油", "unit": "", "amount": ""}, {"name": "生抽", "unit": "", "amount": ""}, {"name": "白糖", "unit": "", "amount": ""}, {"name": "鸡蛋", "unit": "", "amount": ""}]', '[{"order": 1, "content": "肉切片腌制：放点生抽、耗油、盐、胡椒粉、鸡蛋、淀粉"}, {"order": 2, "content": "多放点油，放辣椒、花椒把配菜炒熟盛出来备用"}, {"order": 3, "content": "多放点油，放辣椒、花椒、蒜沫炒香，加入半块火锅底料，一勺郫县豆瓣酱炒香"}, {"order": 4, "content": "翻炒均匀后加入水，加入适量生抽、耗油、盐调味，水开后下肉片煮熟捞出"}, {"order": 5, "content": "在菜顶部加入适量蒜末、干辣椒和花椒，用热油爆香即可。"}]', '/uploads/cmn2oojlw000c3iecrfcmidp3.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.132', '2026-03-23 04:35:40.005') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojm3000d3iec2o22mccu', '芋头五花肉', 'MEAT', '[{"name": "荔浦芋头", "unit": "", "amount": ""}, {"name": "五花肉", "unit": "", "amount": ""}, {"name": "洋葱", "unit": "", "amount": ""}, {"name": "葱姜蒜", "unit": "", "amount": ""}, {"name": "料酒", "unit": "", "amount": ""}, {"name": "生抽", "unit": "", "amount": ""}, {"name": "老抽", "unit": "", "amount": ""}, {"name": "耗油", "unit": "", "amount": ""}, {"name": "胡椒粉", "unit": "", "amount": ""}, {"name": "鸡精", "unit": "", "amount": ""}, {"name": "冰糖", "unit": "", "amount": ""}]', '[{"order": 1, "content": "备菜：芋头削皮切厚片（大概2个硬币厚），姜切片（6/7片），葱切小段，蒜切沫，洋葱切丝"}, {"order": 2, "content": "五花肉焯水：整块放入冷水中，加姜片葱段料酒，大火烧开后撇去浮沫，继续煮20-30min，捞出前可以用筷子扎穿即可，捞出过凉水洗净，切成与芋头薄厚差不多的厚片"}, {"order": 3, "content": "调料汁：姜片+蒜末（2瓣）+干辣椒（掰碎，1-2个）+八角（一个），生抽：耗油：料酒：老抽=3:2:2:1，加入少量胡椒粉、鸡精，4-5块冰糖"}, {"order": 4, "content": "锅底放上洋葱丝，将芋头与五花肉相间摆好（立着放：五花肉-芋头-五花肉），倒入调好的料汁，加入没过一半芋头的水"}, {"order": 5, "content": "大火烧开后转小火，炖20-30min即可出锅。"}]', '/uploads/cmn2oojm3000d3iec2o22mccu.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.139', '2026-03-23 04:35:40.82') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojmb000e3iec9ocpbn8i', '炖鲫鱼', 'MEAT', '[{"name": "鲫鱼", "unit": "", "amount": ""}, {"name": "葱姜蒜", "unit": "", "amount": ""}, {"name": "八角", "unit": "", "amount": ""}, {"name": "甜面酱/豆瓣酱", "unit": "", "amount": ""}, {"name": "生抽", "unit": "", "amount": ""}, {"name": "老抽", "unit": "", "amount": ""}, {"name": "醋", "unit": "", "amount": ""}, {"name": "料酒", "unit": "", "amount": ""}, {"name": "耗油", "unit": "", "amount": ""}, {"name": "白糖", "unit": "", "amount": ""}, {"name": "盐", "unit": "", "amount": ""}]', '[{"order": 1, "content": "备料：鲫鱼杀好去内脏、鱼鳞，洗净备用，准备一壶开水"}, {"order": 2, "content": "调料汁：葱切段、姜切片、蒜整瓣放入碗中，加2颗八角，适量生抽、耗油、料酒、甜面酱，少量老抽、醋、白糖，搅拌均匀备用"}, {"order": 3, "content": "油烧热，把鲫鱼放入锅中煎，中火即可，待一面煎定型后再翻面煎另外一面"}, {"order": 4, "content": "两面煎好后倒入备好的料汁，分散均匀后可加入开水，没过鱼表面，大火烧开后转中小火，炖15-20min，加入盐调味，可适当收汁。"}]', '/uploads/cmn2oojmb000e3iec9ocpbn8i.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.147', '2026-03-23 04:35:41.619') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojmp000f3ieckmpg919l', '西红柿牛腩', 'MEAT', '[{"name": "牛腩", "unit": "", "amount": ""}, {"name": "西红柿", "unit": "", "amount": ""}, {"name": "红薯", "unit": "", "amount": ""}, {"name": "葱姜", "unit": "", "amount": ""}, {"name": "八角", "unit": "", "amount": ""}, {"name": "冰糖", "unit": "", "amount": ""}, {"name": "料酒", "unit": "", "amount": ""}, {"name": "干辣椒", "unit": "", "amount": ""}, {"name": "桂皮", "unit": "", "amount": ""}, {"name": "香叶", "unit": "", "amount": ""}, {"name": "生抽", "unit": "", "amount": ""}, {"name": "老抽", "unit": "", "amount": ""}, {"name": "耗油", "unit": "", "amount": ""}, {"name": "盐", "unit": "", "amount": ""}]', '[{"order": 1, "content": "牛腩切块，西红柿去皮一半切大块一半切小块，分开备用，红薯去皮切滚刀块"}, {"order": 2, "content": "牛腩冷水下锅，加入葱段、姜片，适量料酒，焯至变色捞出洗净备用"}, {"order": 3, "content": "炒糖色：小火倒油，加入冰糖，炒至焦糖色倒入牛腩，翻炒均匀"}, {"order": 4, "content": "加入葱姜、八角、桂皮、香叶、干辣椒炒出香味，加入小块西红柿炒出汁，加入生抽、耗油、老抽（比例为2:2:1）继续翻炒"}, {"order": 5, "content": "加入热水没过牛肉，大火烧开后转小火炖1h以上（或者用压力锅选牛肉模式）"}, {"order": 6, "content": "加入大块西红柿和红薯继续焖煮10min左右，加入盐调味，再焖煮5min开始大火收汁即可。"}]', '/uploads/cmn2oojmp000f3ieckmpg919l.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.161', '2026-03-23 04:35:42.402') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojmv000g3ieccb0w1kbi', '可乐鸡翅', 'MEAT', '[{"name": "鸡翅中", "unit": "", "amount": ""}, {"name": "可乐", "unit": "", "amount": ""}, {"name": "白芝麻", "unit": "", "amount": ""}, {"name": "料酒", "unit": "", "amount": ""}, {"name": "生抽", "unit": "", "amount": ""}, {"name": "老抽", "unit": "", "amount": ""}, {"name": "白糖", "unit": "", "amount": ""}, {"name": "耗油", "unit": "", "amount": ""}]', '[{"order": 1, "content": "腌鸡翅：加入2勺料酒，2勺生抽，多半勺老抽，2勺耗油，半勺白糖，涂抹均匀腌半小时以上"}, {"order": 2, "content": "起锅烧油，油中热时下入腌好的鸡翅煎，煎至两面金黄倒入腌鸡翅的酱料翻炒（酱料倒入少一半即可）"}, {"order": 3, "content": "翻炒约1min左右倒入没过鸡翅的可乐，大火煮开转小火"}, {"order": 4, "content": "小火煮15-20min转大火收汁，期间不断翻炒以防粘锅"}, {"order": 5, "content": "余一点汤汁时即可关火，鸡翅盛出，汤汁洒在鸡翅上，撒入一些白芝麻装饰即可。"}]', '/uploads/cmn2oojmv000g3ieccb0w1kbi.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.167', '2026-03-23 04:35:43.169') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojn0000h3iecipbmkb5j', '小炒肉', 'MEAT', '[{"name": "五花肉", "unit": "", "amount": ""}, {"name": "杭椒", "unit": "", "amount": ""}, {"name": "小米辣", "unit": "", "amount": ""}, {"name": "姜蒜", "unit": "", "amount": ""}, {"name": "胡椒粉", "unit": "", "amount": ""}, {"name": "耗油", "unit": "", "amount": ""}, {"name": "生抽", "unit": "", "amount": ""}, {"name": "老抽", "unit": "", "amount": ""}, {"name": "白糖", "unit": "", "amount": ""}]', '[{"order": 1, "content": "杭椒切成斜段，肉切片，小米辣切丁"}, {"order": 2, "content": "起锅不加油，小火将杭椒、小米辣煸至虎皮状盛出"}, {"order": 3, "content": "加入少量油滑锅，多余油倒出即可，锅热后加入五花肉翻炒，炒至八成熟加入姜蒜沫，翻炒两下加入1勺耗油，1勺生抽、1/3勺老抽，少量的胡椒粉和白糖提味"}, {"order": 4, "content": "翻炒均匀后加入煸好的杭椒和小米辣，炒1-2min即可出锅。"}]', '/uploads/cmn2oojn0000h3iecipbmkb5j.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.172', '2026-03-23 04:35:43.921') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojn5000i3ieckr72kfr7', '鲍鱼红烧肉', 'MEAT', '[{"name": "五花肉", "unit": "", "amount": ""}, {"name": "鲍鱼", "unit": "", "amount": ""}, {"name": "葱姜", "unit": "", "amount": ""}, {"name": "料酒", "unit": "", "amount": ""}, {"name": "生抽", "unit": "", "amount": ""}, {"name": "冰糖", "unit": "", "amount": ""}, {"name": "大料", "unit": "", "amount": ""}]', '[{"order": 1, "content": "将鲍鱼用勺剥离，去掉内脏（绿色那部分）刷净，五花肉切麻将块，凉水下锅焯水，水开后煮2min捞出，用热水清洗冲掉浮沫"}, {"order": 2, "content": "五花肉沥干，放入锅里煸出油，煸至略带金黄色关火，把肉盛出备用，猪油留在锅里"}, {"order": 3, "content": "在煸出的猪油里放入冰糖（5-6粒即可），小火不断的翻炒（炒糖色），炒至焦糖色倒入五花肉"}, {"order": 4, "content": "糖色均匀后加入大料、姜片、葱段翻炒，加入少量料酒，2勺生抽，一点老抽翻炒均匀"}, {"order": 5, "content": "加热水没过肉块，大火烧开后转小火炖45min-1h"}, {"order": 6, "content": "出锅前10min加入鲍鱼，最后大火收汁。"}]', '/uploads/cmn2oojn5000i3ieckr72kfr7.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.177', '2026-03-23 04:35:44.677') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojng000j3iec6ogjb175', '红烧猪蹄', 'MEAT', '[{"name": "猪蹄", "unit": "", "amount": ""}, {"name": "黄豆", "unit": "", "amount": ""}, {"name": "葱姜", "unit": "", "amount": ""}, {"name": "八角", "unit": "", "amount": ""}, {"name": "香叶", "unit": "", "amount": ""}, {"name": "料酒", "unit": "", "amount": ""}, {"name": "冰糖", "unit": "", "amount": ""}, {"name": "生抽", "unit": "", "amount": ""}, {"name": "老抽", "unit": "", "amount": ""}, {"name": "耗油", "unit": "", "amount": ""}, {"name": "盐", "unit": "", "amount": ""}]', '[{"order": 1, "content": "将猪蹄剁成小块（买的时候让老板给剁开），冷水下锅，放入适量料酒、姜片焯水"}, {"order": 2, "content": "焯水后捞出洗净（不要用凉水洗），擦干备用"}, {"order": 3, "content": "炒糖色：小火锅中倒油，微热后取"}, {"order": 4, "content": "7粒冰糖放入锅中，不断扒拉，至冰糖融化成焦糖色即可"}, {"order": 5, "content": "倒入备好的猪蹄，火微微调大一点，翻炒均匀上色"}, {"order": 6, "content": "加入葱段、姜片、八角、香叶翻炒，再放入一勺料酒、一勺生抽、一勺老抽、一勺耗油，可根据菜量酌情加减，继续翻炒"}, {"order": 7, "content": "翻炒均匀后加入开水没过猪蹄，大火烧开后转小火焖炖半小时，加入提前泡好的黄豆继续焖炖一小时，期间注意水量不要烧干"}, {"order": 8, "content": "炖烂即可，加入适量盐再进行大火收汁，后即可出锅。"}]', '/uploads/cmn2oojng000j3iec6ogjb175.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.188', '2026-03-23 04:35:45.457') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojnl000k3iecu1cmv0ra', '排骨炖土豆豆角', 'MEAT', '[{"name": "排骨", "unit": "", "amount": ""}, {"name": "豆角", "unit": "", "amount": ""}, {"name": "土豆", "unit": "", "amount": ""}, {"name": "粉条", "unit": "", "amount": ""}, {"name": "葱姜", "unit": "", "amount": ""}, {"name": "料酒", "unit": "", "amount": ""}, {"name": "冰糖", "unit": "", "amount": ""}, {"name": "八角", "unit": "", "amount": ""}, {"name": "干辣椒", "unit": "", "amount": ""}, {"name": "香叶", "unit": "", "amount": ""}, {"name": "桂皮", "unit": "", "amount": ""}, {"name": "耗油", "unit": "", "amount": ""}, {"name": "生抽", "unit": "", "amount": ""}, {"name": "老抽", "unit": "", "amount": ""}, {"name": "盐", "unit": "", "amount": ""}, {"name": "鸡精", "unit": "", "amount": ""}]', '[{"order": 1, "content": "排骨凉水下锅，放入葱姜和料酒焯水，水开后煮3min捞出洗净（要用温水冲洗）"}, {"order": 2, "content": "冲洗后擦干，小火烧油，微热后放入冰糖慢慢炒化，至焦糖色即可，倒入洗净擦干的排骨翻炒，均匀上色"}, {"order": 3, "content": "上色后放入八角、干辣椒、香叶、桂皮翻炒几下，后加入1:1的生抽和耗油，加入少许老抽，倒入热水没过排骨，大火煮开"}, {"order": 4, "content": "倒入电压力锅选肉选项（或在炒锅内小火炖30-40min），好了以后按难熟顺序加入豆角/土豆/粉条等配菜，继续炖15min左右"}, {"order": 5, "content": "加入盐、鸡精调味，大火收汁即可。"}]', '/uploads/cmn2oojnl000k3iecu1cmv0ra.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.193', '2026-03-23 04:35:46.33') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojnt000l3iect5lj4f07', '荷兰豆炒腊肠', 'MEAT', '[{"name": "甜腊肠", "unit": "", "amount": ""}, {"name": "荷兰豆", "unit": "", "amount": ""}, {"name": "蒜", "unit": "", "amount": ""}, {"name": "盐", "unit": "", "amount": ""}, {"name": "鸡精", "unit": "", "amount": ""}]', '[{"order": 1, "content": "荷兰豆摘净焯水，腊肠切片"}, {"order": 2, "content": "起锅烧油，加入蒜末炝锅，先放入腊肠翻炒"}, {"order": 3, "content": "1min后加入荷兰豆，一起翻炒均匀，加入适量盐和鸡精，翻炒均匀后出锅即可。"}]', '/uploads/cmn2oojnt000l3iect5lj4f07.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.201', '2026-03-23 04:35:47.138') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojnz000m3iecplxq3jms', '鱼汤', 'SOUP', '[{"name": "鲈鱼", "unit": "", "amount": ""}, {"name": "豆腐（嫩豆腐）", "unit": "", "amount": ""}, {"name": "小葱", "unit": "", "amount": ""}, {"name": "姜", "unit": "", "amount": ""}, {"name": "盐", "unit": "", "amount": ""}, {"name": "胡椒粉", "unit": "", "amount": ""}]', '[{"order": 1, "content": "将鲈鱼洗净切段（横切），一定要洗干净；姜切片，小葱切段，豆腐切块"}, {"order": 2, "content": "起锅烧油，油7成热的时候放入姜片，将鱼段放入锅中煎到两面微焦，倒入准备好的开水"}, {"order": 3, "content": "大火烧开后转小火，咕嘟5min左右加入嫩豆腐，继续煮个5-10min"}, {"order": 4, "content": "出锅前1-2min加入适量盐、少量胡椒粉进行调味，加入小葱段即可。"}]', '/uploads/cmn2oojnz000m3iecplxq3jms.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.207', '2026-03-23 04:35:47.957') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojo6000n3iec9y0j7sr2', '菌菇鸡汤', 'SOUP', '[{"name": "鸡（半只）", "unit": "", "amount": ""}, {"name": "菌菇汤包", "unit": "", "amount": ""}, {"name": "红枣", "unit": "", "amount": ""}, {"name": "盐", "unit": "", "amount": ""}]', '[{"order": 1, "content": "鸡剁开切块，加入葱姜料酒焯水3-4min，焯后捞出洗净"}, {"order": 2, "content": "把菌菇汤包泡发洗净备用，枣洗净备用"}, {"order": 3, "content": "将锅中加入清水大火烧热，放入焯好的鸡块，烧开后20min，加入菌菇包和洗净的枣，再熬煮半小时以上"}, {"order": 4, "content": "出锅前5-6min加入适量盐调味即可"}, {"order": 5, "content": "出锅之前盛出一碗递给心爱的人。"}]', '/uploads/cmn2oojo6000n3iec9y0j7sr2.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.214', '2026-03-23 04:35:48.757') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojo9000o3iecyr7o52p1', '玉米山药排骨汤', 'SOUP', '[{"name": "排骨", "unit": "", "amount": ""}, {"name": "山药", "unit": "", "amount": ""}, {"name": "玉米", "unit": "", "amount": ""}, {"name": "胡萝卜", "unit": "", "amount": ""}, {"name": "枸杞", "unit": "", "amount": ""}, {"name": "红枣", "unit": "", "amount": ""}, {"name": "葱姜", "unit": "", "amount": ""}, {"name": "油", "unit": "", "amount": ""}, {"name": "盐", "unit": "", "amount": ""}, {"name": "鸡精", "unit": "", "amount": ""}]', '[{"order": 1, "content": "排骨凉水下锅焯水，放入葱段姜片料酒，水开后煮2min捞出洗净"}, {"order": 2, "content": "炒锅锅底刷油，中小火将排骨炒至表面金黄，加入热水大火烧开"}, {"order": 3, "content": "转砂锅（也可以不转）小火炖45min，加入玉米、红枣继续煮10min，再加入山药、胡萝卜煮15min左右"}, {"order": 4, "content": "加入盐和少量鸡精调味，煮2min可盛出食用。"}]', '/uploads/cmn2oojo9000o3iecyr7o52p1.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.217', '2026-03-23 04:35:49.592') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojoh000p3iecvqllwi3v', '葱花口蘑汤', 'SOUP', '[{"name": "口蘑", "unit": "", "amount": ""}, {"name": "小葱", "unit": "", "amount": ""}, {"name": "盐", "unit": "", "amount": ""}]', '[{"order": 1, "content": "将口蘑去根洗净，锅底不刷油开小火，将口蘑烤至出水"}, {"order": 2, "content": "将口蘑出的水倒入锅中用剪子剪开放入锅中，加入开水"}, {"order": 3, "content": "煮开后加入少量盐，煮3min左右撒入葱花即可出锅。"}]', '/uploads/cmn2oojoh000p3iecvqllwi3v.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.225', '2026-03-23 04:35:50.364') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojol000q3iecpw5b16hl', '彩椒杏鲍菇炒虾仁', 'MEAT', '[{"name": "彩椒", "unit": "", "amount": ""}, {"name": "杏鲍菇", "unit": "", "amount": ""}, {"name": "虾仁", "unit": "", "amount": ""}, {"name": "蒜", "unit": "", "amount": ""}, {"name": "生抽", "unit": "", "amount": ""}, {"name": "盐", "unit": "", "amount": ""}, {"name": "耗油", "unit": "", "amount": ""}, {"name": "鸡精", "unit": "", "amount": ""}]', '[{"order": 1, "content": "备菜：彩椒、杏鲍菇切丝，蒜切片，虾仁洗净备用"}, {"order": 2, "content": "小火倒油（别太少，杏鲍菇吸油），加入蒜片扒拉几下，下入杏鲍菇，翻炒均匀后加少量盐，炒至出水"}, {"order": 3, "content": "加入彩椒，翻炒均匀后加入虾仁，再翻炒几下加入适量生抽（2勺左右），少量耗油，继续翻炒均匀"}, {"order": 4, "content": "出锅之前加入适量盐、鸡精即可。"}]', '/uploads/cmn2oojol000q3iecpw5b16hl.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.229', '2026-03-23 04:35:51.132') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojoo000r3iechz8f4ugt', '土豆牛肉粒', 'MEAT', '[{"name": "牛肉（里脊）", "unit": "", "amount": ""}, {"name": "土豆", "unit": "", "amount": ""}, {"name": "葱姜", "unit": "", "amount": ""}, {"name": "生抽", "unit": "", "amount": ""}, {"name": "耗油", "unit": "", "amount": ""}, {"name": "白胡椒粉", "unit": "", "amount": ""}, {"name": "辣椒面", "unit": "", "amount": ""}, {"name": "孜然面", "unit": "", "amount": ""}, {"name": "白芝麻", "unit": "", "amount": ""}]', '[{"order": 1, "content": "土豆和牛肉切丁（骰子大小即可），切好后牛肉加入适量耗油、生抽、白胡椒粉、食用油腌制十分钟"}, {"order": 2, "content": "起锅烧油，油热后放入腌好的牛肉丁，均匀翻炒30s左右变色即可捞出，再放入切好的土豆丁进行煎炒，炒至金黄色盛出备用"}, {"order": 3, "content": "放入葱蒜末炒香，放入土豆和牛肉丁翻炒，加入适量耗油、生抽，翻炒均匀后再加入适量孜然面、辣椒粉、白熟芝麻，翻炒均匀，加入葱花即可出锅。"}]', '/uploads/cmn2oojoo000r3iechz8f4ugt.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.232', '2026-03-23 04:35:51.985') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojos000s3iec243fope3', '凉拌杏鲍菇', 'VEGETABLE', '[{"name": "杏鲍菇", "unit": "", "amount": ""}, {"name": "香菜", "unit": "", "amount": ""}, {"name": "小米辣", "unit": "", "amount": ""}, {"name": "蒜", "unit": "", "amount": ""}, {"name": "辣椒面", "unit": "", "amount": ""}, {"name": "孜然面", "unit": "", "amount": ""}, {"name": "白芝麻", "unit": "", "amount": ""}, {"name": "醋", "unit": "", "amount": ""}, {"name": "生抽", "unit": "", "amount": ""}, {"name": "耗油", "unit": "", "amount": ""}, {"name": "糖", "unit": "", "amount": ""}]', '[{"order": 1, "content": "杏鲍菇洗净后竖着切成两半上锅蒸（俩人建议至少三个杏鲍菇，不出量）15分钟，蒸熟以后过凉水撕成条"}, {"order": 2, "content": "香菜切小段放进撕好的杏鲍菇里，准备料汁"}, {"order": 3, "content": "料汁：加入一勺孜然粉、一勺辣椒粉、2个小米辣、3-4瓣的蒜末、一点白芝麻，淋上热油；放入2勺醋、一勺生抽、一勺半耗油、半勺白糖搅拌均匀"}, {"order": 4, "content": "将料汁淋到杏鲍菇和香菜上，搅拌均匀即可。"}]', '/uploads/cmn2oojos000s3iec243fope3.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.236', '2026-03-23 04:35:52.85') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojow000t3iecbbj90ahl', '香辣虾', 'MEAT', '[{"name": "大虾（最好是鲜活的）", "unit": "", "amount": ""}, {"name": "尖椒（看能吃辣的程度选）", "unit": "", "amount": ""}, {"name": "葱姜", "unit": "", "amount": ""}, {"name": "料酒", "unit": "", "amount": ""}, {"name": "白糖", "unit": "", "amount": ""}, {"name": "生抽", "unit": "", "amount": ""}, {"name": "耗油", "unit": "", "amount": ""}, {"name": "盐", "unit": "", "amount": ""}, {"name": "鸡精", "unit": "", "amount": ""}]', '[{"order": 1, "content": "备菜：虾去一小半头（剪子把眼睛及以下部位剪掉）和须，辣椒掰块，葱姜切成沫"}, {"order": 2, "content": "起锅烧油，放进葱姜沫炒香，把虾倒入锅中炒到变色"}, {"order": 3, "content": "加入一勺料酒、一小勺白糖，放入辣椒"}, {"order": 4, "content": "翻炒均匀后，加入一勺生抽、一勺耗油和一小勺盐，翻炒均匀，出锅前加入鸡精即可。"}]', '/uploads/cmn2oojow000t3iecbbj90ahl.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.24', '2026-03-23 04:35:53.692') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojp0000u3iecwjyr8lpp', '茄子炖土豆', 'MEAT', '[{"name": "茄子", "unit": "", "amount": ""}, {"name": "土豆", "unit": "", "amount": ""}, {"name": "尖椒", "unit": "", "amount": ""}, {"name": "香菜", "unit": "", "amount": ""}, {"name": "葱", "unit": "", "amount": ""}, {"name": "蒜", "unit": "", "amount": ""}, {"name": "豆瓣酱", "unit": "", "amount": ""}, {"name": "生抽", "unit": "", "amount": ""}, {"name": "老抽", "unit": "", "amount": ""}, {"name": "耗油", "unit": "", "amount": ""}]', '[{"order": 1, "content": "备菜：土豆和茄子去皮切滚刀块，尖椒切小碎丁、香菜切小段"}, {"order": 2, "content": "起锅烧油（多一点），小火先把土豆和茄子煎到金黄，加入两勺豆瓣酱（可适当多一点点）、两勺生抽、一勺蚝油、多半勺老抽炒匀"}, {"order": 3, "content": "加入热水没过食材，大火烧开后转小火炖15分钟，看茄子和土豆的状态，如果还有大块，那铲子怼怼"}, {"order": 4, "content": "开始大火收汁，到全面冒泡且黏糊的状态了加入尖椒丁和香菜段搅拌均匀，整体比较粘稠了即可出锅"}, {"order": 5, "content": "盛一碗大米饭，盖上黏糊糊的茄子炖土豆，开始拌饭！"}]', '/uploads/cmn2oojp0000u3iecwjyr8lpp.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.244', '2026-03-23 04:35:54.457') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojp3000v3iecgd4ccytt', '黄焖排骨', 'MEAT', '[{"name": "肋排", "unit": "", "amount": ""}, {"name": "土豆", "unit": "", "amount": ""}, {"name": "干香菇", "unit": "", "amount": ""}, {"name": "尖椒", "unit": "", "amount": ""}, {"name": "小米辣（一两根就行）", "unit": "", "amount": ""}, {"name": "姜片", "unit": "", "amount": ""}, {"name": "洋葱", "unit": "", "amount": ""}, {"name": "料酒", "unit": "", "amount": ""}, {"name": "生抽", "unit": "", "amount": ""}, {"name": "蚝油", "unit": "", "amount": ""}, {"name": "胡椒粉", "unit": "", "amount": ""}, {"name": "鸡精", "unit": "", "amount": ""}]', '[{"order": 1, "content": "备菜：肋排切小块，干香菇用热水泡发，土豆切滚刀小块，尖椒切滚刀段，小米辣切小段，洋葱切小丁"}, {"order": 2, "content": "排骨凉水下锅，加入料酒、姜片焯水"}, {"order": 3, "content": "起锅烧油，先将土豆煎至金黄盛出"}, {"order": 4, "content": "下入适量冰糖炒糖色（六七个，可根据排骨量调整），炒至焦糖色时下入排骨翻炒，让排骨均匀裹上糖色"}, {"order": 5, "content": "放洋葱丁翻炒出味，加入泡好的干香菇翻炒，加入一勺蚝油、一勺生抽，少量胡椒粉和鸡精翻炒均匀，加入热水，大火烧开后转小火炖30-40分钟"}, {"order": 6, "content": "加入土豆翻炒均匀，再焖炖10分钟左右，加入尖椒和小米辣，大火收汁，收至适量即可出锅"}]', '/uploads/cmn2oojp3000v3iecgd4ccytt.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.247', '2026-03-23 04:35:55.265') ON CONFLICT DO NOTHING;
INSERT INTO public."Recipe" VALUES ('cmn2oojp7000w3iecy3a569ih', '江西辣翅', 'MEAT', '[{"name": "鸡翅", "unit": "", "amount": ""}, {"name": "蒜苗", "unit": "", "amount": ""}, {"name": "香菜", "unit": "", "amount": ""}, {"name": "姜", "unit": "", "amount": ""}, {"name": "蒜", "unit": "", "amount": ""}, {"name": "小米辣", "unit": "", "amount": ""}, {"name": "料酒", "unit": "", "amount": ""}, {"name": "生抽", "unit": "", "amount": ""}, {"name": "老抽", "unit": "", "amount": ""}, {"name": "淀粉", "unit": "", "amount": ""}, {"name": "白胡椒粉", "unit": "", "amount": ""}, {"name": "啤酒", "unit": "", "amount": ""}, {"name": "豆瓣酱", "unit": "", "amount": ""}, {"name": "油辣子", "unit": "", "amount": ""}, {"name": "白糖/冰糖", "unit": "", "amount": ""}, {"name": "辣椒粉", "unit": "", "amount": ""}]', '[{"order": 1, "content": "备菜腌制：鸡翅剪开，加入1:1:1的料酒、生抽、老抽，一勺淀粉和白胡椒粉，抓匀，封油腌制10min；姜、蒜切末，小米辣切丁，蒜苗、香菜切段"}, {"order": 2, "content": "热锅凉油，油比炒菜略多一点，下腌制好的鸡翅煎一下，煎至双面变色开始翻炒"}, {"order": 3, "content": "加入姜蒜末、小米辣爆炒，翻炒均匀后加入一听啤酒、一勺豆瓣酱、一勺油辣子、一勺白糖或者三四块冰糖，一大勺辣椒粉，盖上盖子转中小火焖煮"}, {"order": 4, "content": "大约10-15分钟后转大火收汁，收至快好了的时候加入香菜和蒜苗翻炒，收汁至差不多出锅。"}]', '/uploads/cmn2oojp7000w3iecy3a569ih.jpg', 'cmn2n5vf6000clyecv2csc7bx', 'cmn2mgvi10003lyec6ijhnvzb', '2026-03-23 04:26:32.251', '2026-03-23 04:35:56.042') ON CONFLICT DO NOTHING;
